#include "archsynth/search/evolution.h"
#include <algorithm>
namespace archsynth { Evolution::Evolution(EvolutionConfig c,std::unique_ptr<Evaluator> e,std::unique_ptr<Mutation> m,std::unique_ptr<LLMMutator> l):config_(c),evaluator_(std::move(e)),mutation_(std::move(m)),llm_mutator_(std::move(l)){} std::pair<Genotype,double> Evolution::run(const ConditionVector& cond,std::mt19937& rng){ EvolutionState s; s.population=Population::initialize(config_.population_size,rng,cond); for(int gen=0; gen<config_.max_generations; ++gen){ s.fitness=evaluator_->evaluate_population(s.population); std::vector<size_t> idx(s.population.size()); for(size_t i=0;i<idx.size();++i) idx[i]=i; std::sort(idx.begin(),idx.end(),[&](size_t a,size_t b){return s.fitness[a]>s.fitness[b];}); if(s.fitness[idx[0]]>s.best_fitness){ s.best_fitness=s.fitness[idx[0]]; s.best_genotype=s.population[idx[0]]; s.generations_no_improvement=0; } else ++s.generations_no_improvement; std::vector<Genotype> next; int elites=std::max(1,(int)(config_.elite_ratio*config_.population_size)); for(int i=0;i<elites&&i<(int)idx.size();++i) next.push_back(s.population[idx[i]]); std::uniform_int_distribution<int> d(0,std::max(0,(int)s.population.size()-1)); while((int)next.size()<config_.population_size){ auto child=s.population[d(rng)]; mutation_->apply(child,rng,cond); next.push_back(child); } if(config_.use_llm_assist&&llm_mutator_&&s.generations_no_improvement>config_.stagnation_patience){ auto extras=llm_mutator_->propose_mutations(s.best_genotype,{},s.best_fitness,rng); for(auto&g:extras) if(!next.empty()) next.back()=g; } s.population=std::move(next); } return {s.best_genotype,s.best_fitness}; } }
